const n=new IntersectionObserver(e=>e.forEach(t=>{t.isIntersecting&&t.target.classList.add("visible")}),{threshold:.1});document.querySelectorAll(".fade-up").forEach(e=>n.observe(e));const o=document.getElementById("mobile-toggle"),s=document.getElementById("mobile-menu"),c=document.getElementById("icon-open"),d=document.getElementById("icon-close");o?.addEventListener("click",()=>{const e=s?.classList.toggle("hidden");c?.classList.toggle("hidden",!e),d?.classList.toggle("hidden",!!e)});
